INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('APEX2_1: Le email engagement curve: l engagement est le plus haut au signup, puis decline. L objectif de chaque email est de MAINTENIR l engagement, pas juste vendre.', 'Email engagement: plus haut au signup puis decline. Maintenir pas juste vendre', 'email', 'insight', 0.85, 'apex2', 'system'),
('APEX2_2: Le commercial proposal timing: envoyer la proposition < 24h apres le call de decouverte. Apres 48h, la motivation baisse de 40%.', 'Proposal < 24h post-call. > 48h = -40% motivation', 'commercial', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_3: Le content creation workflow: idee → brief → creation → edit → review → schedule → publish → distribute → measure → iterate. 10 etapes.', 'Content workflow: idee→brief→creation→edit→review→schedule→publish→distribute→measure→iterate', 'content', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_4: Le SEO content update signal: Google favorise les pages avec une date de mise a jour recente. Ajouter "Mis a jour le [date]" et mettre a jour reellement le contenu.', 'SEO update signal: date MAJ recente + contenu reellement mis a jour = favorise', 'seo', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_5: Le ad creative iteration: prendre la creative gagnante, changer 1 element (hook, couleur, CTA, format), tester. Repetez jusqu a ce que plus rien ne s ameliore.', 'Creative iteration: changer 1 element gagnant → tester → repetez', 'ads', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_6: Le DM micro-personalization: mentionner 1 detail specifique du profil du prospect (dernier post, bio, story recente). Le generique est invisible.', 'DM micro-perso: 1 detail specifique profil. Generique = invisible', 'dm_instagram', 'best_practice', 0.88, 'apex2', 'system'),
('APEX2_7: Le WhatsApp catalog product page: chaque produit dans le catalogue doit avoir: photo HD, titre < 40 chars, description < 100 chars, prix, lien.', 'WhatsApp catalogue: photo HD + titre 40 + desc 100 + prix + lien/produit', 'whatsapp', 'best_practice', 0.80, 'apex2', 'system'),
('APEX2_8: Le chatbot proactive engagement triggers: page pricing > 30s, page FAQ scroll > 80%, page contact idle > 10s, page panier idle > 15s.', 'Chatbot proactive: pricing>30s, FAQ scroll>80%, contact>10s, panier>15s', 'chatbot', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_9: Le GMaps review request QR code placement: a la caisse, sur le ticket, sur la carte de visite, sur l emballage, dans le mail de confirmation. 5 touchpoints.', 'GMaps QR review: caisse + ticket + carte + emballage + email = 5 touchpoints', 'gmaps', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_10: Le TikTok profile optimization: photo pro, bio claire avec CTA + lien, videos epinglees (3 meilleurs), highlight des meilleurs commentaires.', 'TikTok profil: photo pro + bio CTA + lien + 3 videos epinglees + highlights', 'tiktok_comments', 'best_practice', 0.80, 'apex2', 'system'),
('APEX2_11: Le CEO strategic focus: chaque trimestre, choisir 1 seul objectif strategique. Pas 5. Un seul. Toutes les ressources convergent vers cet objectif.', 'CEO: 1 objectif strategique/trimestre. Pas 5. Un seul = convergence', 'ceo', 'best_practice', 0.88, 'apex2', 'system'),
('APEX2_12: Le retention churn root cause analysis: pour chaque churner, identifier: manque de valeur (45%), prix (20%), concurrent (15%), bug/UX (10%), autre (10%).', 'Churn root cause: manque valeur 45%, prix 20%, concurrent 15%, bug 10%, autre 10%', 'retention', 'insight', 0.82, 'apex2', 'system'),
('APEX2_13: Le onboarding email sequence complete: J0 bienvenue (instant) → J1 quick win → J3 feature highlight → J5 case study → J7 check-in → J14 upgrade CTA.', 'Onboarding email: J0→J1→J3→J5→J7→J14. 6 emails en 2 semaines', 'onboarding', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_14: Le comptable unit economics checklist: LTV calculé? CAC calculé? Ratio > 3? Payback < 12m? Gross margin > 70%? Si 4/5 oui = unit economics sains.', 'Unit economics checklist: LTV + CAC + ratio>3 + payback<12 + margin>70%. 4/5 = sain', 'comptable', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_15: Le RH team retrospective format: 3 colonnes: ce qui a marche (keep), ce qui n a pas marche (stop), ce qu on devrait essayer (start). 30 min max.', 'Retro: Keep/Stop/Start. 30 min max', 'rh', 'best_practice', 0.80, 'apex2', 'system'),
('APEX2_16: Le marketing positioning statement: pour [cible] qui [probleme], [produit] est [categorie] qui [benefice unique] contrairement a [alternative].', 'Positioning: pour cible qui probleme, produit est categorie qui benefice vs alternative', 'marketing', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_17: Le cross-agent customer lifecycle automation: decouverte (ads+content) → interet (email+DM) → consideration (commercial+chatbot) → achat → onboarding → adoption → expansion → advocacy.', 'Lifecycle auto: ads→email+DM→commercial+chatbot→achat→onboard→adopt→expand→advocate', NULL, 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_18: Le data hygiene automation: chaque semaine, supprimer les doublons CRM, les emails bounced, les prospects sans activite 90j+, les tags inutilises.', 'Data hygiene hebdo: doublons + bounced + inactifs 90j + tags inutilises = supprimer', NULL, 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_19: Le KeiroAI agent calibration: chaque mois, comparer les outputs de chaque agent aux best practices du secteur. Recalibrer les prompts si necessaire.', 'Agent calibration mensuelle: comparer outputs vs best practices. Recalibrer prompts', NULL, 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_20: Le KeiroAI growth flywheel: agents performants → clients satisfaits → referrals → plus de clients → plus de data RAG → agents plus performants.', 'KeiroAI flywheel: agents → satisfaits → referrals → clients → data → agents mieux', 'ceo', 'insight', 0.90, 'apex2', 'system'),
('APEX2_21: Le email inbox warm-up rotation: 5 boites email en rotation pour le cold outreach. Si 1 tombe en spam, les 4 autres continuent. Diversifier le risque.', 'Email warm-up: 5 boites rotation cold. 1 spam = 4 continuent. Diversifier risque', 'email', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_22: Le commercial deal champion test: votre champion peut-il pitcher votre solution a son boss en 30 secondes? Si non → lui fournir le pitch deck simplifie.', 'Champion test: pitcher en 30s a son boss? Non → fournir pitch deck simplifie', 'commercial', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_23: Le content 10x rule: chaque contenu cree doit etre 10x meilleur que le meilleur contenu existant sur ce sujet. Sinon il ne percera pas dans le bruit.', 'Content 10x: 10x meilleur que le meilleur existant. Sinon = bruit', 'content', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_24: Le SEO hreflang implementation: pour les sites FR+EN, chaque page doit avoir hreflang fr pour la version FR et hreflang en pour la version EN + x-default.', 'Hreflang: page FR hreflang=fr, EN hreflang=en + x-default', 'seo', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_25: Le ad post-click experience: la landing page doit reprendre EXACTEMENT le meme message que l ad. Meme headline, meme visuel, meme offre. Coherence = conversion.', 'Post-click: landing = meme headline + visuel + offre que ad. Coherence = conversion', 'ads', 'best_practice', 0.88, 'apex2', 'system'),
('APEX2_26: Le DM response time impact: repondre a un DM < 5 minutes = 4x plus de chances de conversion vs > 1 heure. La vitesse est tout.', 'DM response < 5 min = 4x conversion vs > 1h. Vitesse = tout', 'dm_instagram', 'insight', 0.85, 'apex2', 'system'),
('APEX2_27: Le WhatsApp business verification: obtenir le badge vert (verifie) = +50% confiance client. Necessite: compte business API, documents legaux, verification Meta.', 'WhatsApp badge vert = +50% confiance. API + documents + verification Meta', 'whatsapp', 'insight', 0.80, 'apex2', 'system'),
('APEX2_28: Le chatbot user satisfaction measurement: apres chaque conversation, poser 1 question: "Cette reponse vous a-t-elle aide? 👍 ou 👎". Simple et actionable.', 'Chatbot satisfaction: 1 question fin "aide? 👍👎". Simple actionable', 'chatbot', 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_29: Le GMaps local authority score: nombre d avis × note moyenne × completude fiche × citations × backlinks locaux = score d autorite local.', 'GMaps authority: avis × note × completude × citations × backlinks = score', 'gmaps', 'insight', 0.80, 'apex2', 'system'),
('APEX2_30: Le TikTok hashtag strategy 2026: 3-5 hashtags max. 1 broad (#business), 2 medium (#entrepreneurfr), 2 niche (#restaurateurparis). Dans la caption.', 'TikTok hashtags 2026: 3-5 max. 1 broad + 2 medium + 2 niche. Dans caption', 'tiktok_comments', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_31: Le CEO brief for clients must-haves: 1) ton CA/leads cette semaine vs derniere, 2) ce que vos agents ont fait de concret, 3) votre action #1 pour cette semaine.', 'CEO brief client: CA comparatif + actions agents concretes + 1 action client', 'ceo', 'best_practice', 0.88, 'apex2', 'system'),
('APEX2_32: Le retention feature depth correlation: les clients qui utilisent 5+ features ont un taux de churn de 2% vs 15% pour ceux qui n en utilisent que 1-2.', 'Feature depth: 5+ features = 2% churn vs 1-2 features = 15% churn', 'retention', 'insight', 0.88, 'apex2', 'system'),
('APEX2_33: Le onboarding welcome call impact: un appel de bienvenue de 10 minutes dans les 24h post-signup augmente la retention J30 de 30%.', 'Welcome call 10min < 24h = +30% retention J30', 'onboarding', 'insight', 0.82, 'apex2', 'system'),
('APEX2_34: Le comptable SaaS COGS breakdown: hosting (Vercel, Supabase) + API costs (OpenAI, Claude) + email (Brevo, Resend) + support tools. Total < 30% du revenu.', 'SaaS COGS: hosting + API + email + support. Total < 30% revenu', 'comptable', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_35: Le RH competency matrix: pour chaque role, definir 5-7 competences cles avec 4 niveaux (debutant, intermediaire, avance, expert). Evaluer chaque employe.', 'Competency matrix: 5-7 competences × 4 niveaux/role. Evaluer chaque employe', 'rh', 'best_practice', 0.78, 'apex2', 'system'),
('APEX2_36: Le marketing cross-channel campaign planning: 1 message → adapter pour 5+ canaux (email, social, ads, DM, content) → lancer simultanement → mesurer par canal.', 'Cross-channel: 1 message → 5+ canaux adaptes → lancer ensemble → mesurer/canal', 'marketing', 'best_practice', 0.82, 'apex2', 'system'),
('APEX2_37: Le agent performance monitoring automated: chaque heure, verifier: executions reussies, echecs, temps de reponse, cout API. Alerte si anomalie > 2 ecarts-types.', 'Agent monitoring: executions+echecs+temps+cout. Alerte si > 2 ecarts-types', NULL, 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_38: Le customer success leading indicators: feature adoption velocity (combien de nouvelles features adoptees/mois), time-in-app trend, support ticket sentiment trend.', 'CS leading: feature adoption velocity + time-in-app trend + ticket sentiment trend', NULL, 'insight', 0.82, 'apex2', 'system'),
('APEX2_39: Le KeiroAI RAG quality assurance: chaque learning ajoute au RAG est evalue: pertinence (1-5), specificite (1-5), actionabilite (1-5). Score < 9 = rejete.', 'RAG QA: pertinence + specificite + actionabilite sur 5. < 9 = rejete', NULL, 'best_practice', 0.85, 'apex2', 'system'),
('APEX2_40: Le KeiroAI ultimate competitive advantage: l accumulation de 10 000+ learnings experts, enrichis par chaque client, accessible a chaque agent = intelligence marketing sans precedent.', 'KeiroAI: 10K+ learnings + enrichi par clients + accessible agents = intelligence sans precedent', 'ceo', 'best_practice', 0.95, 'apex2', 'system')
